  ('optician-moex-00097', 'optician', 'optician-moex-114-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '當一副眼鏡對配戴者的右眼產生2ΔBU，左眼產生3ΔBD，這副眼鏡對於配戴者左眼相較於右眼共產生了多 少稜鏡量？', '["5ΔBU", "5ΔBD", "1ΔBU", "1ΔBD"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "4ab6aaf4ddf7", "answer_pdf_sha1": "f89a96eaed88", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 45, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
